function countClass(val) {
    if (val > 2)
    return 'count-hot';
    if (val > 0)
    return 'count-pos';
    if (val < 0)
    return 'count-neg';
    return 'count-neutral';
}
function cellClass(code) {
    var map = {
    H: 's-H', S: 's-S', D: 's-D', Ds: 's-Ds',
    SP: 's-SP', 'Y/N': 's-SY', SUR: 's-SUR',
    };
    return map[code] || '';
}
function actionClass(action) {
    var map = {
    HIT: 'action-hit',
    STAND: 'action-stand',
    DOUBLE: 'action-double',
    'DOUBLE DOWN': 'action-double',
    SPLIT: 'action-split',
    SURRENDER: 'action-surrender',
    };
    return map[action] || '';
}
function showToast(msg, type = 'info') {
    var container = document.getElementById('toasts');
    if (!container)
    return;
    var el = document.createElement('div');
    el.className = `toast ${type}`;
    el.textContent = msg;
    container.appendChild(el);
    setTimeout(() => {
    el.style.opacity = '0';
    el.style.transform = 'translateX(20px)';
    setTimeout(() => el.remove(), 300);
    }, 3500);
}
function formatMoney(n, currencySymbol) {
    var sym = currencySymbol || '₹';
    var abs = Math.abs(n || 0);
    return `${(n || 0) >= 0 ? '+' : '-'}${sym}${abs.toFixed(0)}`;
}
